#!/usr/bin/env python
import subprocess
import os
import sys
import time
from datetime import datetime

ALLOWED_FORMATS = ['tar.gz', 'tar.bz2', 'zip', '7z']

def validate_directory(directory_path):
    if not directory_path:
        raise ValueError("Directory path cannot be empty")
    
    abs_path = os.path.abspath(directory_path)
    
    if not os.path.exists(abs_path):
        raise ValueError(f"Directory does not exist: {abs_path}")
    
    if not os.path.isdir(abs_path):
        raise ValueError(f"Path is not a directory: {abs_path}")
    
    return abs_path

def validate_format(format_type):
    if format_type not in ALLOWED_FORMATS:
        raise ValueError(f"Invalid format. Allowed formats: {', '.join(ALLOWED_FORMATS)}")
    return format_type

def get_archive_name(directory_path, format_type):
    dir_name = os.path.basename(directory_path.rstrip(os.sep))
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    
    if format_type == 'tar.gz':
        extension = '.tar.gz'
    elif format_type == 'tar.bz2':
        extension = '.tar.bz2'
    elif format_type == 'zip':
        extension = '.zip'
    elif format_type == '7z':
        extension = '.7z'
    else:
        extension = '.tar.gz'
    
    return f"{dir_name}_backup_{timestamp}{extension}"

def create_tar_gz_backup(directory_path, archive_name):
    parent_dir = os.path.dirname(directory_path)
    target_dir = os.path.basename(directory_path)
    
    cmd = ['tar', '-czf', archive_name, '-C', parent_dir, target_dir]
    subprocess.run(cmd, check=True, shell=False)
    return archive_name

def create_tar_bz2_backup(directory_path, archive_name):
    parent_dir = os.path.dirname(directory_path)
    target_dir = os.path.basename(directory_path)
    
    cmd = ['tar', '-cjf', archive_name, '-C', parent_dir, target_dir]
    subprocess.run(cmd, check=True, shell=False)
    return archive_name

def create_zip_backup(directory_path, archive_name):
    parent_dir = os.path.dirname(directory_path)
    target_dir = os.path.basename(directory_path)
    
    cmd = ['zip', '-r', archive_name, target_dir]
    subprocess.run(cmd, check=True, shell=False, cwd=parent_dir)
    return archive_name

def create_7z_backup(directory_path, archive_name):
    cmd = ['7z', 'a', '-t7z', archive_name, directory_path]
    subprocess.run(cmd, check=True, shell=False)
    return archive_name

def create_backup(directory_path, format_type):
    validated_path = validate_directory(directory_path)
    validated_format = validate_format(format_type)
    
    archive_name = get_archive_name(validated_path, validated_format)
    
    print(f"Creating backup of: {validated_path}")
    print(f"Format: {validated_format}")
    print(f"Archive name: {archive_name}")
    
    start_time = time.time()
    
    try:
        if validated_format == 'tar.gz':
            result = create_tar_gz_backup(validated_path, archive_name)
        elif validated_format == 'tar.bz2':
            result = create_tar_bz2_backup(validated_path, archive_name)
        elif validated_format == 'zip':
            result = create_zip_backup(validated_path, archive_name)
        elif validated_format == '7z':
            result = create_7z_backup(validated_path, archive_name)
        else:
            raise ValueError(f"Unsupported format: {validated_format}")
        
        elapsed_time = time.time() - start_time
        
        if os.path.exists(result):
            file_size = os.path.getsize(result)
            size_mb = file_size / (1024 * 1024)
            print(f"\nBackup completed successfully!")
            print(f"Archive: {result}")
            print(f"Size: {size_mb:.2f} MB")
            print(f"Time: {elapsed_time:.2f} seconds")
            return result
        else:
            raise RuntimeError("Archive creation failed - file not found")
            
    except subprocess.CalledProcessError as e:
        print(f"Error: Backup process failed with exit code {e.returncode}")
        sys.exit(1)
    except Exception as e:
        print(f"Error: {str(e)}")
        sys.exit(1)

def main():
    if len(sys.argv) != 3:
        print("Usage: python backup_script.py <directory_path> <format>")
        print(f"Supported formats: {', '.join(ALLOWED_FORMATS)}")
        sys.exit(1)
    
    directory_path = sys.argv[1]
    format_type = sys.argv[2]
    
    create_backup(directory_path, format_type)

if __name__ == '__main__':
    main()